const raw = $input.item.json;
const plaintext = raw.plaintext || '';

// Erstes Zeichen = Nachrichtentyp-Byte
const msgTypeByte = plaintext.codePointAt(0);

// Alles nach dem ersten Byte, PKCS7-Padding abschneiden
// Padding sind Bytes 0x01-0xFF am Ende - einfach bis zur schließenden } schneiden
const jsonPart = plaintext.substring(1);
const jsonEnd = jsonPart.lastIndexOf('}');
const jsonStr = jsonEnd >= 0 ? jsonPart.substring(0, jsonEnd + 1) : jsonPart;

let parsed = null;
try {
  parsed = JSON.parse(jsonStr);
} catch(e) {}

let msgType = 'unknown';
let isImage = false;
let isText = false;
let blobId = '';
let blobKey = '';
let text = '';

if (msgTypeByte === 0x02) {
  // Text-Nachricht
  msgType = 'text';
  isText = true;
  text = jsonPart.substring(0, jsonEnd >= 0 ? jsonEnd : undefined);
} else if (msgTypeByte === 0x17 && parsed) {
  // Datei-Nachricht (so sendet Threema Bilder)
  msgType = 'file';
  isImage = (parsed.m || '').startsWith('image/');
  blobId = parsed.b || '';
  blobKey = parsed.k || '';
}

return {
  msgType,
  hasBlob: isImage,
  blobId,
  blobKey,
  text,
  from: $('Config').item.json.from,
  isImage,
  isText,
  raw
};

const kiAntwort = $json.choices?.[0]?.message?.content || '{}';
const config = $('Config').item.json;

let kiDaten;
try {
  kiDaten = JSON.parse(kiAntwort);
} catch(e) {
  kiDaten = { fehler: 'JSON-Parse fehlgeschlagen', raw: kiAntwort };
}

// Beleg-Nummer: B-YYYY-NNNN wird von Supabase-Funktion vergeben
// Pseudonymisierung: vendor_id wird separat via identity-Schema gesetzt
const beleg = {
  eingangskanal: 'threema',
  threema_sender_id: config.from,
  mandant_id: $('Mandant ermitteln').item.json[0]?.id ?? null,
  status: 'vorschlag',
  beleg_datum: kiDaten.beleg_datum || null,
  betrag_brutto: kiDaten.betrag_brutto || null,
  betrag_netto: kiDaten.betrag_netto || null,
  mwst_satz: kiDaten.mwst_satz || null,
  mwst_betrag: kiDaten.mwst_betrag || null,
  beleg_typ: kiDaten.beleg_typ || 'sonstiges',
  verwendungszweck: kiDaten.verwendungszweck || null,
  sachkonto: kiDaten.sachkonto_vorschlag || '6890',
  sachkonto_ki_vorschlag: kiDaten.sachkonto_vorschlag || '6890',
  sachkonto_manuell_geaendert: false,
  ocr_konfidenz: kiDaten.konfidenz || null,
  // Beleg-Nr via Supabase-Funktion
  beleg_nr_placeholder: true
};

return [{
  json: {
    beleg,
    lieferant_name: kiDaten.lieferant_name || null,
    sachkonto_begruendung: kiDaten.sachkonto_begruendung || null,
    from: config.from,
    threemaFrom: config.threemaFrom,
    secret1: config.secret1
  }
}];

